import React, { Component } from 'react';
import { withRouter, Link } from 'react-router-dom';
import s from './Upload.module.scss';
import Icon from '../../Icons/base';

import Article from './Article/Article';
import Post from './Post/Post';

class Upload extends Component {

    constructor(props) {
        super(props);
        this.state = {
            pub_type: 0
        };

        this.choosePublicationType = this.choosePublicationType.bind(this);
    }

    choosePublicationType(type) {
        if (type === 1 || type === 2) {
            this.setState({ pub_type: type });
        }
    }

    render() {
        const { pub_type } = this.state;

        return (
            <>
            <div className={s.main}>
                <div className={s['choose-box']}>
                    <div className={s['choose-box__header']}>
                        <h3 className="bs-title">Opublikuj</h3>
                    </div>
                    <div className={s['choose-box__items']}>
                        <div className={[s['choose-item'], pub_type == 1 ? s['choose-item--active']:null].join(' ')} onClick={() => this.choosePublicationType(1)}>
                            <Icon name="article"/>
                            <h5>Artykuł</h5>
                        </div>
                        <div className={[s['choose-item'], pub_type == 2 ? s['choose-item--active']:null].join(' ')} onClick={() => this.choosePublicationType(2)}>
                            <Icon name="image"/>
                            <h5>Krótki post</h5>
                        </div>
                    </div>
                </div>
            </div>
            <div className={s.content}>
                {pub_type === 1 ? <Article pub={this.state.pub_type}/> : null}
                {pub_type === 2 ? <Post pub={this.state.pub_type}/> : null}
            </div>
            </>
        )
    }
}

export default withRouter(Upload);
